
-- Insert 60+ properties from around the world in ENGLISH with proper casting
INSERT INTO properties (broker_id, title, description, type, price, currency, price_eur, size_sqm, bedrooms, bathrooms, country, city, address, latitude, longitude, photos, status, domus_score, created_at) 
