  (SELECT id FROM profiles WHERE account_type = 'broker' LIMIT 1),
  title, description, type::property_type, price, currency, price_eur, size_sqm, bedrooms, bathrooms, country, city, address, latitude::numeric, longitude::numeric, photos, status::property_status, domus_score, NOW()
